// ============================================================
// MAPA (componente reutilizable basado en Leaflet)
// ============================================================
function LeafletMap({ markers = [], polylines = [], height = '400px', center = [10.4703, -66.6193], zoom = 13 }) {
  const mapRef = useRef(null);
  const mapInstanceRef = useRef(null);
  const [ready, setReady] = useState(false);

  // Cargar Leaflet dinámicamente
  useEffect(() => {
    const loadLeaflet = async () => {
      if (window.L) { setReady(true); return; }
      // CSS
      const link = document.createElement('link');
      link.rel = 'stylesheet';
      link.href = 'https://unpkg.com/leaflet@1.9.4/dist/leaflet.css';
      document.head.appendChild(link);
      // JS
      await new Promise((resolve) => {
        const script = document.createElement('script');
        script.src = 'https://unpkg.com/leaflet@1.9.4/dist/leaflet.js';
        script.onload = resolve;
        document.head.appendChild(script);
      });
      setReady(true);
    };
    loadLeaflet();
  }, []);

  // Inicializar mapa
  useEffect(() => {
    if (!ready || !mapRef.current || mapInstanceRef.current) return;
    const L = window.L;
    const map = L.map(mapRef.current, { 
      zoomControl: true, 
      attributionControl: false,
      scrollWheelZoom: true,
      doubleClickZoom: true,
      touchZoom: true,
    }).setView(center, zoom);
    // Mapa estilo OpenStreetMap a color (similar a Google Maps)
    L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
      maxZoom: 19,
      subdomains: ['a', 'b', 'c'],
    }).addTo(map);
    // Control de escala (km/m visible)
    L.control.scale({ imperial: false, metric: true, position: 'bottomleft' }).addTo(map);
    mapInstanceRef.current = map;
  }, [ready]);

  // Actualizar marcadores y rutas
  useEffect(() => {
    if (!mapInstanceRef.current || !window.L) return;
    const L = window.L;
    const map = mapInstanceRef.current;

    // Limpiar capas previas
    map.eachLayer(layer => {
      if (layer instanceof L.Marker || layer instanceof L.Polyline || layer instanceof L.CircleMarker) {
        map.removeLayer(layer);
      }
    });

    // Polylines (recorridos)
    polylines.forEach(p => {
      if (p.points && p.points.length > 1) {
        L.polyline(p.points, { color: p.color || '#10b981', weight: 3, opacity: 0.8 }).addTo(map);
      }
    });

    // Marcadores
    markers.forEach(m => {
      if (m.type === 'branch') {
        const icon = L.divIcon({
          className: 'custom-marker',
          html: `<div style="background:${m.isCenter ? '#f59e0b' : '#10b981'}; color:white; padding:6px 10px; border-radius:8px; font-size:11px; font-weight:bold; white-space:nowrap; box-shadow:0 2px 8px rgba(0,0,0,0.5); border:1px solid rgba(255,255,255,0.2);">📍 ${m.name}</div>`,
          iconSize: [120, 30],
          iconAnchor: [60, 15],
        });
        L.marker([m.lat, m.lng], { icon }).addTo(map);
      } else if (m.type === 'vehicle') {
        const icon = L.divIcon({
          className: 'custom-marker',
          html: `<div style="background:${m.color}; color:white; padding:8px 12px; border-radius:50px; font-size:13px; font-weight:900; box-shadow:0 4px 16px ${m.color}80; border:2px solid white; animation:pulse-marker 2s infinite;">🚛 ${m.code}</div>`,
          iconSize: [100, 36],
          iconAnchor: [50, 18],
        });
        const marker = L.marker([m.lat, m.lng], { icon }).addTo(map);
        if (m.popup) marker.bindPopup(m.popup);
      }
    });

    // Auto-ajustar vista si hay marcadores
    if (markers.length > 0 || polylines.length > 0) {
      const allPoints = [
        ...markers.map(m => [m.lat, m.lng]),
        ...polylines.flatMap(p => p.points || []),
      ];
      if (allPoints.length > 1) {
        try { map.fitBounds(allPoints, { padding: [40, 40], maxZoom: 14 }); } catch (e) {}
      }
    }
  }, [markers, polylines, ready]);

  return (
    <>
      <style>{`
        @keyframes pulse-marker {
          0%, 100% { transform: scale(1); }
          50% { transform: scale(1.08); }
        }
        .leaflet-container { background: #e5e7eb !important; }
        .leaflet-popup-content-wrapper { background:#ffffff !important; color:#1c1917 !important; border-radius:12px !important; box-shadow:0 4px 16px rgba(0,0,0,0.3); }
        .leaflet-popup-content { font-family: system-ui; font-size: 13px; }
        .leaflet-popup-tip { background:#ffffff !important; }
        .leaflet-control-zoom a { background:#ffffff !important; color:#1c1917 !important; border:1px solid #d6d3d1 !important; font-weight:bold !important; }
        .leaflet-control-zoom a:hover { background:#f5f5f4 !important; }
        .leaflet-control-scale { background:rgba(255,255,255,0.85) !important; padding:2px 6px !important; border-radius:4px !important; }
      `}</style>
      <div ref={mapRef} style={{ height, width: '100%', borderRadius: '16px', overflow: 'hidden' }}>
        {!ready && (
          <div className="h-full bg-stone-100 flex items-center justify-center text-emerald-700 font-mono text-sm">
            <div className="flex items-center gap-2">
              <div className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"></div>
              CARGANDO MAPA...
            </div>
          </div>
        )}
      </div>
    </>
  );
}

// ============================================================
// APP DEL CHOFER
// ============================================================
function DriverApp({ currentDriver, onLogout, vehicles, drivers, branches, trips, activeTrips, photos, gpsTracks, saveTrips, saveActiveTrips, saveVehicles, savePhotos, saveGpsTracks, checklists, saveChecklists, config }) {
  const [tab, setTab] = useState('trip');
  const [step, setStep] = useState('select');
  const [selectedVehicle, setSelectedVehicle] = useState(null);
  const [currentTrip, setCurrentTrip] = useState(null);
  const [gpsEnabled, setGpsEnabled] = useState(false);
  const [currentPosition, setCurrentPosition] = useState(null);
  const watchIdRef = useRef(null);

  const myTrips = useMemo(() => trips.filter(t => t.driverId === currentDriver.id), [trips, currentDriver]);
  const myActiveTrips = useMemo(() => activeTrips.filter(t => t.driverId === currentDriver.id), [activeTrips, currentDriver]);
  const myPhotos = useMemo(() => photos.filter(p => p.driverId === currentDriver.id), [photos, currentDriver]);

  useEffect(() => {
    if (selectedVehicle) {
      const active = myActiveTrips.find(t => t.vehicleId === selectedVehicle.id);
      if (active) { setCurrentTrip(active); setStep('active'); }
    }
  }, [selectedVehicle, myActiveTrips]);

  // Estado para velocidad y alertas
  const lastSpeedAlertRef = useRef(0);

  // GPS Tracking
  const startGpsTracking = (tripId) => {
    if (!navigator.geolocation) return;
    setGpsEnabled(true);
    watchIdRef.current = navigator.geolocation.watchPosition(
      (pos) => {
        // Velocidad: usar la del GPS si está disponible (m/s → km/h),
        // sino calcular desde el punto anterior
        let speedKmh = 0;
        if (pos.coords.speed != null && pos.coords.speed >= 0) {
          speedKmh = pos.coords.speed * 3.6;
        } else {
          // Cálculo manual desde el último punto
          const existing = gpsTracks.find(g => g.tripId === tripId);
          const lastPoint = existing?.points?.[existing.points.length - 1];
          if (lastPoint) {
            const R = 6371; // Radio Tierra en km
            const dLat = (pos.coords.latitude - lastPoint.lat) * Math.PI / 180;
            const dLng = (pos.coords.longitude - lastPoint.lng) * Math.PI / 180;
            const a = Math.sin(dLat / 2) ** 2 + Math.cos(lastPoint.lat * Math.PI / 180) * Math.cos(pos.coords.latitude * Math.PI / 180) * Math.sin(dLng / 2) ** 2;
            const dist = 2 * R * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a)); // km
            const dt = (Date.now() - lastPoint.t) / 3600000; // horas
            if (dt > 0) speedKmh = dist / dt;
          }
        }
        // Filtrar valores extraños (mayor a 200 km/h probablemente es error de GPS)
        if (speedKmh > 200) speedKmh = 0;

        const point = { lat: pos.coords.latitude, lng: pos.coords.longitude, t: Date.now(), speed: speedKmh, accuracy: pos.coords.accuracy };
        setCurrentPosition(point);

        // Alerta por exceso de velocidad (más de 100 km/h)
        // Solo notificar a Discord 1 vez cada 60 segundos para no spamear
        if (speedKmh > 100 && Date.now() - lastSpeedAlertRef.current > 60000) {
          lastSpeedAlertRef.current = Date.now();
          const v = vehicles.find(x => x.id === (selectedVehicle?.id || currentTrip?.vehicleId));
          // 🔊 ALERTA DE VOZ al chofer
          speakText('¡Atención! Estás superando el límite. Reduce la velocidad por tu seguridad.');
          const webhookUrl = v ? config.discordWebhookByVehicle?.[v.id] : '';
          if (webhookUrl) {
            fetch(webhookUrl, {
              method: 'POST',
              headers: { 'Content-Type': 'application/json' },
              body: JSON.stringify({
                embeds: [{
                  title: `🚨 EXCESO DE VELOCIDAD - ${v.code}`,
                  description: `**${currentDriver.shortName}** está conduciendo a **${Math.round(speedKmh)} km/h** (límite 80).\n📍 Posición: ${point.lat.toFixed(5)}, ${point.lng.toFixed(5)}`,
                  color: 16711680, // Rojo
                  timestamp: new Date().toISOString(),
                }],
              }),
            }).catch(e => console.warn('Discord alert error:', e));
          }
        }

        // Guardar punto del recorrido
        const existing = gpsTracks.find(g => g.tripId === tripId);
        if (existing) {
          const updated = gpsTracks.map(g => g.tripId === tripId ? { ...g, points: [...g.points, point] } : g);
          saveGpsTracks(updated);
        } else {
          saveGpsTracks([...gpsTracks, { tripId, driverId: currentDriver.id, vehicleId: selectedVehicle?.id || currentTrip?.vehicleId, points: [point], startedAt: Date.now() }]);
        }
      },
      (err) => { console.warn('GPS error', err); setGpsEnabled(false); },
      { enableHighAccuracy: true, maximumAge: 5000, timeout: 15000 }
    );
  };
  const stopGpsTracking = () => {
    if (watchIdRef.current !== null) {
      navigator.geolocation.clearWatch(watchIdRef.current);
      watchIdRef.current = null;
    }
    setGpsEnabled(false);
  };
  useEffect(() => () => stopGpsTracking(), []);

  const startTrip = (data) => {
    // Calcular tiempo en sucursal de destino del viaje anterior
    const lastTripSameVehicle = [...trips].filter(t => t.vehicleId === selectedVehicle.id).sort((a, b) => b.createdAt - a.createdAt)[0];
    if (lastTripSameVehicle && lastTripSameVehicle.destinationBranchId === data.originBranchId) {
      const arrivedMs = parseDateTime(lastTripSameVehicle.endDate, lastTripSameVehicle.endTime);
      const departMs = parseDateTime(data.startDate, data.startTime);
      const minutes = Math.max(0, Math.round((departMs - arrivedMs) / 60000));
      saveTrips(trips.map(t => t.id === lastTripSameVehicle.id
        ? { ...t, timeAtDestinationMinutes: minutes, departedDestinationAt: `${data.startDate}T${data.startTime}` }
        : t));
    }

    const trip = {
      id: `at_${Date.now()}`,
      driverId: currentDriver.id, vehicleId: selectedVehicle.id,
      originBranchId: data.originBranchId, destinationBranchId: data.destinationBranchId,
      kmStart: Number(data.kmStart), startTime: data.startTime, startDate: data.startDate,
      fuelLoaded: Number(data.fuelLoaded) || 0,
    };
    saveActiveTrips([...activeTrips, trip]);
    setCurrentTrip(trip);
    setStep('active');

    // Iniciar GPS
    startGpsTracking(trip.id);

    // Beep de confirmación
    playBeep();

    // Notificación Discord
    const origin = branches.find(b => b.id === data.originBranchId);
    const dest = branches.find(b => b.id === data.destinationBranchId);
    const webhookUrl = config.discordWebhookByVehicle?.[selectedVehicle.id] || config.discordWebhookGeneral;
    sendDiscordNotification(webhookUrl, {
      title: `🚛 VIAJE INICIADO · ${selectedVehicle.code}`,
      description: `**${currentDriver.name}** salió de **${origin?.name}** rumbo a **${dest?.name}**`,
      color: 0x10b981,
      fields: [
        { name: '⏰ Hora', value: data.startTime, inline: true },
        { name: '📊 KM', value: data.kmStart.toLocaleString(), inline: true },
        { name: '⛽ Surtido', value: data.fuelLoaded ? `${data.fuelLoaded} L` : 'Sin carga', inline: true },
      ],
      footer: { text: `Transporte Emporium · ${new Date().toLocaleString('es-VE')}` },
    });
  };

  const finishTrip = (data) => {
    const v = vehicles.find(x => x.id === currentTrip.vehicleId);
    const kmTraveled = Math.max(0, Number(data.kmEnd) - currentTrip.kmStart);
    const liters = (kmTraveled * (v.litersPer100km || 21)) / 100;
    const cost = liters * config.fuelPrice;
    const startMs = parseDateTime(currentTrip.startDate, currentTrip.startTime);
    const endMs = parseDateTime(data.endDate, data.endTime);
    const tripMinutes = Math.max(0, Math.round((endMs - startMs) / 60000));

    const prevTrip = [...trips].filter(t => t.vehicleId === currentTrip.vehicleId && t.destinationBranchId === currentTrip.originBranchId)
      .sort((a, b) => parseDateTime(b.endDate, b.endTime) - parseDateTime(a.endDate, a.endTime))[0];
    let timeAtBranch = null;
    if (prevTrip) timeAtBranch = Math.max(0, Math.round((startMs - parseDateTime(prevTrip.endDate, prevTrip.endTime)) / 60000));

    const completed = {
      id: `t_${Date.now()}`, driverId: currentTrip.driverId, vehicleId: currentTrip.vehicleId,
      originBranchId: currentTrip.originBranchId, destinationBranchId: currentTrip.destinationBranchId,
      kmStart: currentTrip.kmStart, kmEnd: Number(data.kmEnd), kmTraveled,
      startDate: currentTrip.startDate, startTime: currentTrip.startTime,
      endDate: data.endDate, endTime: data.endTime, tripMinutes, timeAtBranchPrevMinutes: timeAtBranch,
      liters: Number(liters.toFixed(2)), fuelPrice: config.fuelPrice, cost: Number(cost.toFixed(2)),
      deliveries: Number(data.deliveries) || 0, tripsCount: Number(data.tripsCount) || 1,
      route: data.route || 'LOCAL', fuelLoaded: currentTrip.fuelLoaded || 0, notes: data.notes || '',
      createdAt: Date.now(),
    };

    saveTrips([...trips, completed]);
    saveActiveTrips(activeTrips.filter(t => t.id !== currentTrip.id));
    if (Number(data.kmEnd) > v.currentKm) saveVehicles(vehicles.map(x => x.id === v.id ? { ...x, currentKm: Number(data.kmEnd) } : x));

    // Asociar GPS track con el viaje completado
    saveGpsTracks(gpsTracks.map(g => g.tripId === currentTrip.id ? { ...g, tripId: completed.id, completed: true } : g));

    stopGpsTracking();
    setCurrentTrip(completed);
    setStep('finish');

    // Beep de confirmación
    playBeep();

    // Notificación Discord
    const origin = branches.find(b => b.id === currentTrip.originBranchId);
    const dest = branches.find(b => b.id === currentTrip.destinationBranchId);
    const webhookUrl = config.discordWebhookByVehicle?.[v.id] || config.discordWebhookGeneral;
    sendDiscordNotification(webhookUrl, {
      title: `✅ VIAJE COMPLETADO · ${v.code}`,
      description: `**${currentDriver.name}** llegó a **${dest?.name}** desde **${origin?.name}**`,
      color: 0x059669,
      fields: [
        { name: '🛣️ KM Recorridos', value: `${kmTraveled} km`, inline: true },
        { name: '⏱️ Duración', value: formatDuration(tripMinutes), inline: true },
        { name: '⛽ Combustible', value: `${liters.toFixed(2)} L`, inline: true },
        { name: '💵 Costo', value: `$${cost.toFixed(2)}`, inline: true },
        { name: '📦 Entregas', value: `${data.deliveries || 0}`, inline: true },
        { name: '🕐 Hora llegada', value: data.endTime, inline: true },
      ],
      footer: { text: `Transporte Emporium · ${new Date().toLocaleString('es-VE')}` },
    });
  };

  const cancelActiveTrip = () => {
    // La confirmación se maneja con un modal en ActiveTripView
    saveActiveTrips(activeTrips.filter(t => t.id !== currentTrip.id));
    saveGpsTracks(gpsTracks.filter(g => g.tripId !== currentTrip.id));
    stopGpsTracking();
    setCurrentTrip(null);
    onLogout();
  };
  const newTrip = () => { setCurrentTrip(null); setStep('select'); };
  const markDepartedDestination = (tripId) => {
    const trip = trips.find(t => t.id === tripId);
    if (!trip) return;
    const arrivedMs = parseDateTime(trip.endDate, trip.endTime);
    const now = new Date();
    const departTime = now.toTimeString().slice(0, 5);
    const departDate = now.toISOString().slice(0, 10);
    const minutes = Math.max(0, Math.round((Date.now() - arrivedMs) / 60000));
    saveTrips(trips.map(t => t.id === tripId ? { ...t, timeAtDestinationMinutes: minutes, departedDestinationAt: `${departDate}T${departTime}` } : t));
  };

  const addPhoto = (photo) => {
    const vehicleForPhoto = selectedVehicle || (currentTrip && vehicles.find(v => v.id === currentTrip.vehicleId));
    const p = {
      id: `p_${Date.now()}`, driverId: currentDriver.id,
      vehicleId: vehicleForPhoto?.id || '', tripId: currentTrip?.id || null,
      ...photo, createdAt: Date.now(), date: new Date().toISOString().slice(0, 10),
    };
    savePhotos([...photos, p]);

    // Enviar notificación a Discord según categoría
    let webhookUrl = '';
    let channelName = '';
    if (photo.category === 'maintenance' || photo.category === 'fuel') {
      webhookUrl = config.discordWebhookMaintenance;
      channelName = '#info-servicio-Mantenimiento';
    } else {
      // Transferencia o Daño/Incidente → canal general
      webhookUrl = config.discordWebhookGeneral;
      channelName = '#grupo-transporte-en-general';
    }
    if (!webhookUrl) return;

    const categoryLabels = {
      transfer: '📄 Transferencia',
      fuel: '⛽ Combustible',
      incident: '⚠️ Daño/Incidente',
      maintenance: '🔧 Mantenimiento',
    };
    const colors = { transfer: 0x3b82f6, fuel: 0xf59e0b, incident: 0xef4444, maintenance: 0x10b981 };
    sendDiscordNotification(webhookUrl, {
      title: `${categoryLabels[photo.category] || '📸 Foto'} · ${vehicleForPhoto?.code || 'sin unidad'}`,
      description: `**${currentDriver.name}** subió una foto${photo.description ? `\n📝 ${photo.description}` : ''}`,
      color: colors[photo.category] || 0x6b7280,
      footer: { text: `Transporte Emporium · ${new Date().toLocaleString('es-VE')}` },
    });
  };
  const deletePhoto = (id) => { if (confirm('¿Eliminar?')) savePhotos(photos.filter(p => p.id !== id)); };

  return (
    <div className="min-h-screen bg-stone-100 text-stone-900">
      <header className="bg-gradient-to-r from-[#1a1d1a] via-[#252726] to-[#1a1d1a] border-b border-stone-700 px-4 py-3 flex items-center justify-between sticky top-0 z-30 shadow-xl">
        <div className="flex items-center gap-3">
          <div className="bg-stone-50 rounded-lg p-1 shadow-md">
            <img src={LOGO_TRUCK} alt="" className="w-10 h-6 object-contain" />
          </div>
          <div className="h-6 w-px bg-stone-600"></div>
          <div className="bg-amber-500 w-10 h-10 rounded-xl flex items-center justify-center font-black text-white shadow-lg">
            {currentDriver.shortName.charAt(0)}
          </div>
          <div>
            <div className="font-bold text-white leading-tight">{currentDriver.shortName}</div>
            <div className="text-[10px] text-stone-300 uppercase tracking-wider flex items-center gap-1.5">
              {gpsEnabled && <><div className="w-1.5 h-1.5 bg-emerald-400 rounded-full animate-pulse"></div> GPS ACTIVO</>}
              {!gpsEnabled && 'CHOFER'}
            </div>
          </div>
        </div>
        <div className="flex items-center gap-2">
          <VoiceToggleButton />
          <button onClick={() => { stopGpsTracking(); onLogout(); }} className="text-stone-300 hover:text-white text-sm flex items-center gap-1.5 px-3 py-1.5 rounded-lg hover:bg-white/10 transition">
            <LogOut className="w-4 h-4" /> Salir
          </button>
        </div>
      </header>

      <div className="bg-white border-b border-stone-200 sticky top-[60px] z-20 shadow-sm">
        <div className="max-w-lg mx-auto flex">
          <DriverTabBtn active={tab === 'trip'} onClick={() => setTab('trip')} icon={Navigation} label="Viaje" />
          <DriverTabBtn active={tab === 'photos'} onClick={() => setTab('photos')} icon={Camera} label="Fotos" />
          <DriverTabBtn active={tab === 'history'} onClick={() => setTab('history')} icon={History} label="Historial" />
          <DriverTabBtn active={tab === 'contacts'} onClick={() => setTab('contacts')} icon={Phone} label="Contactos" />
        </div>
      </div>

      <main className="max-w-lg mx-auto p-4 pb-24">
        {tab === 'trip' && <>
          {step === 'select' && <SelectVehicleOnly vehicles={vehicles} selectedVehicle={selectedVehicle} setSelectedVehicle={setSelectedVehicle} onContinue={() => setStep('checklist')} />}
          {step === 'checklist' && selectedVehicle && <ChecklistScreen vehicle={selectedVehicle} driver={currentDriver} checklists={checklists} saveChecklists={saveChecklists} onProceed={() => setStep('start')} onBack={() => setStep('select')} config={config} />}
          {step === 'start' && <StartTripForm driver={currentDriver} vehicle={selectedVehicle} branches={branches} trips={myTrips} onBack={() => setStep('checklist')} onStart={startTrip} />}
          {step === 'active' && currentTrip && <ActiveTripView trip={currentTrip} driver={currentDriver} vehicle={vehicles.find(v => v.id === currentTrip.vehicleId)} branches={branches} onFinish={finishTrip} onCancel={cancelActiveTrip} onAddPhoto={addPhoto} gpsEnabled={gpsEnabled} currentPosition={currentPosition} />}
          {step === 'finish' && currentTrip && <TripCompleteView trip={currentTrip} driver={currentDriver} vehicle={vehicles.find(v => v.id === currentTrip.vehicleId)} branches={branches} onNewTrip={newTrip} onLogout={onLogout} onMarkDeparted={markDepartedDestination} />}
        </>}
        {tab === 'photos' && <PhotosView photos={myPhotos} vehicles={vehicles} drivers={drivers} onAdd={addPhoto} onDelete={deletePhoto} canAdd={true} />}
        {tab === 'history' && <DriverHistoryView trips={myTrips} vehicles={vehicles} branches={branches} />}
        {tab === 'contacts' && <DriverContactsView drivers={drivers} currentDriver={currentDriver} />}
      </main>
    </div>
  );
}

